parameters.jsonBody:
={
  "trigger_id": "{{ $json.trigger_id }}",
  "view": {
    "type": "modal",
    "callback_id": "meeting_check",
    "private_metadata": "{{ JSON.stringify({channel_id: $json.channel_id, user_id: $json.user_id, user_name: $json.user_name}) }}",
    "title": { "type": "plain_text", "text": "✅ 会議の確認事項" },
    "submit": { "type": "plain_text", "text": "送信" },
    "close": { "type": "plain_text", "text": "閉じる" },
    "blocks": [
      {
        "type": "context",
        "elements": [ { "type": "mrkdwn", "text": "会議では *必ず3つの質問・確認事項* を記録するルールです。①〜③は全て必須入力です。" } ]
      },
      {
        "type": "input", "block_id": "meeting_title",
        "label": { "type": "plain_text", "text": "会議名・議題" },
        "element": { "type": "plain_text_input", "action_id": "value", "placeholder": { "type": "plain_text", "text": "例: 週次定例 / ◯◯案件キックオフ" } }
      },
      {
        "type": "input", "block_id": "meeting_date",
        "label": { "type": "plain_text", "text": "開催日" },
        "element": { "type": "datepicker", "action_id": "value" }
      },
      {
        "type": "input", "block_id": "attendees",
        "label": { "type": "plain_text", "text": "参加者" },
        "element": { "type": "plain_text_input", "action_id": "value", "placeholder": { "type": "plain_text", "text": "例: 長谷川, 佐藤, 田中" } }
      },
      {
        "type": "input", "block_id": "check_1",
        "label": { "type": "plain_text", "text": "確認事項① (必須)" },
        "element": { "type": "plain_text_input", "action_id": "value", "multiline": true }
      },
      {
        "type": "input", "block_id": "check_2",
        "label": { "type": "plain_text", "text": "確認事項② (必須)" },
        "element": { "type": "plain_text_input", "action_id": "value", "multiline": true }
      },
      {
        "type": "input", "block_id": "check_3",
        "label": { "type": "plain_text", "text": "確認事項③ (必須)" },
        "element": { "type": "plain_text_input", "action_id": "value", "multiline": true }
      },
      {
        "type": "input", "block_id": "owner",
        "label": { "type": "plain_text", "text": "担当・次アクション" },
        "element": { "type": "plain_text_input", "action_id": "value", "multiline": true },
        "optional": true
      }
    ]
  }
}
